const e=`{% block sw_extension_uninstall_modal %} <sw-modal class="sw-extension-uninstall-modal" :title="title" variant="small" @modal-close="emitClose" > {% block sw_extension_uninstall_modal_content %} <template #default> {% block sw_installed_extension_card_removal_content_modal_body %} <p> {{ $t('sw-extension-store.component.sw-extension-uninstall-modal.description') }} </p> <p class="sw-extension-uninstall-modal__bold-paragraph"> {{ $t('sw-extension-store.component.sw-extension-uninstall-modal.alert') }} </p> <p> <mt-switch v-model="removePluginData" :label="$t('sw-extension-store.component.sw-extension-uninstall-modal.labelRemovePluginData')" :help-text="$t('sw-extension-store.component.sw-extension-uninstall-modal.helpTextRemovePluginData')" /> </p> {% endblock %} </template> <template #modal-footer> {% block sw_extension_uninstall_modal_footer %} {% block sw_extension_uninstall_modal_footer_cancel %} <mt-button size="small" :disabled="isLoading" variant="secondary" @click="emitClose" > {{ $t('global.default.cancel') }} </mt-button> {% endblock %} {% block sw_extension_uninstall_modal_footer_uninstall %} <mt-button variant="critical" size="small" :is-loading="isLoading" @click="emitUninstall" > {{ $t('sw-extension-store.component.sw-extension-uninstall-modal.buttonLabel') }} </mt-button> {% endblock %} {% endblock %} </template> {% endblock %} </sw-modal> {% endblock %}`,t={template:e,emits:["modal-close","uninstall-extension"],props:{extensionName:{type:String,required:!0},isLicensed:{type:Boolean,required:!0},isLoading:{type:Boolean,required:!0}},data(){return{removePluginData:!1}},computed:{title(){return this.$t("sw-extension-store.component.sw-extension-uninstall-modal.title",{extensionName:this.extensionName})}},methods:{emitClose(){this.isLoading||this.$emit("modal-close")},emitUninstall(){this.$emit("uninstall-extension",this.removePluginData)}}};export{t as default};
